function solve(s) {
    const n = s.length;
    let maxLen = 0;

    // Helper function to find the longest balanced subarray in a given string t
    // A subarray is balanced if count('0') == count('1')
    const findMaxBalancedSubarray = (t) => {
        let max_l = 0;
        const balance = new Array(t.length + 1).fill(0);
        // balance[i] = count('1') - count('0') in t[0...i-1]
        for (let i = 0; i < t.length; i++) {
            balance[i + 1] = balance[i] + (t[i] === '1' ? 1 : -1);
        }

        // Map to store the first occurrence of a balance value
        const firstOccurrence = new Map();
        firstOccurrence.set(0, 0);

        for (let j = 1; j <= t.length; j++) {
            const currentBalance = balance[j];
            if (firstOccurrence.has(currentBalance)) {
                const i = firstOccurrence.get(currentBalance);
                // Length of subarray t[i...j-1] is j - i
                max_l = Math.max(max_l, j - i);
            } else {
                firstOccurrence.set(currentBalance, j);
            }
        }
        return max_l;
    };

    // Case 0: No swap
    maxLen = Math.max(maxLen, findMaxBalancedSubarray(s));

    // Case 1: Perform exactly one swap
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            // Create the new string s_prime after swapping s[i] and s[j]
            const s_chars = s.split('');
            [s_chars[i], s_chars[j]] = [s_chars[j], s_chars[i]];
            const s_prime = s_chars.join('');

            // Find the max balanced subarray in the modified string
            maxLen = Math.max(maxLen, findMaxBalancedSubarray(s_prime));
