    /**
     * Helper function to find the longest balanced subarray in a given string t.
     * A subarray is balanced if count('0') == count('1').
     * This uses the prefix sum (balance) technique.
     */
    private static int findMaxBalancedSubarray(String t) {
        int maxL = 0;
        // balance[i] = count('1') - count('0') in t[0...i-1]
        // We use a map to store the first index where a certain balance was achieved.
        java.util.Map<Integer, Integer> firstOccurrence = new java.util.HashMap<>();
        firstOccurrence.put(0, 0); // Balance 0 is achieved before the string starts (at index 0)

        int currentBalance = 0;

        for (int j = 0; j < t.length(); j++) {
            if (t.charAt(j) == '1') {
                currentBalance += 1;
            } else { // t.charAt(j) == '0'
                currentBalance -= 1;
            }

            if (firstOccurrence.containsKey(currentBalance)) {
                int i = firstOccurrence.get(currentBalance);
                // Length of subarray t[i...j] is j - i + 1
                maxL = Math.max(maxL, j - i + 1);
            } else {
                firstOccurrence.put(currentBalance, j + 1); // Store the index *after* the element
            }
        }
        return maxL;
    }

