     */
    private static int findMaxBalancedSubarray(String t) {
        int n = t.length();
        // balance[i] = count('1') - count('0') in t[0...i-1]
        int[] balance = new int[n + 1];
        for (int i = 0; i < n; i++) {
            balance[i + 1] = balance[i] + (t.charAt(i) == '1' ? 1 : -1);
