class Solution {
    /**
     * Finds the maximum length of a balanced substring after at most one swap.
     * A balanced string has an equal number of '0's and '1's.
     *
     * @param s The binary string.
     * @return The maximum length of a balanced substring.
     */
    public static long solve(String s) {
        int n = s.length();
        long maxLen = 0;

        // Helper function to find the longest balanced subarray in a given string t
        // A subarray is balanced if count('0') == count('1'), which means the balance (count('1') - count('0')) is 0.
        java.util.function.Function<String, Integer> findMaxBalancedSubarray = (t) -> {
            int max_l = 0;
            // balance[i] = count('1') - count('0') in t[0...i-1]
            java.util.Map<Integer, Integer> firstOccurrence = new java.util.HashMap<>();
            firstOccurrence.put(0, 0);

            int currentBalance = 0;
            for (int j = 0; j < t.length(); j++) {
                if (t.charAt(j) == '1') {
                    currentBalance++;
                } else {
                    currentBalance--;
                }

                if (firstOccurrence.containsKey(currentBalance)) {
                    int i = firstOccurrence.get(currentBalance);
                    // Length of subarray t[i...j] is j - i + 1.
                    // Since firstOccurrence stores the index *before* the start of the prefix,
                    // if balance[j+1] = balance[i], the length is (j+1) - i.
                    // Here, j+1 is the current prefix length, and i is the start index offset.
                    max_l = Math.max(max_l, j - firstOccurrence.get(currentBalance));
                } else {
                    firstOccurrence.put(currentBalance, j + 1);
                }
            }
            return max_l;
        };

        // Case 0: No swap
        maxLen = Math.max(maxLen, findMaxBalancedSubarray.apply(s));

        // Case 1: Perform exactly one swap
        char[] sChars = s.toCharArray();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                // Perform swap
                char temp = sChars[i];
                sChars[i] = sChars[j];
                sChars[j] = temp;
                String sPrime = new String(sChars);

                // Find the max balanced subarray in the modified string
                maxLen = Math.max(maxLen, findMaxBalancedSubarray.apply(sPrime));

                // Undo swap to restore sChars for the next iteration
                temp = sChars[i];
                sChars[i] = sChars[j];
                sChars[j] = temp;
            }
        }

        return maxLen;
    }
}
